const auth = require('../src/auth');

describe('Authentication', () => {
  const validToken = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VySWQiOjEyMywiZXhwIjoxNzM1MDAwMDAwfQ.signature';
  const expiredToken = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VySWQiOjEyMywiZXhwIjoxNjAwMDAwMDAwfQ.signature';
  const invalidSigToken = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VySWQiOjEyMywiZXhwIjoxNzM1MDAwMDAwfQ.wrongsig';

  test('should validate JWT tokens correctly', () => {
    const result = auth.validateToken(validToken);
    expect(result.valid).toBe(true);
    expect(result.userId).toBe(123);
  });

  test('should reject expired tokens', () => {
    const result = auth.validateToken(expiredToken);
    expect(result.valid).toBe(false);
    expect(result.reason).toBe('expired');
  });

  test('should handle invalid signatures', () => {
    const result = auth.validateToken(invalidSigToken);
    expect(result.valid).toBe(false);
    expect(result.reason).toBe('invalid_signature');
  });

  test('should generate tokens', () => {
    const token = auth.generateToken(123);
    expect(token).toBeDefined();
    expect(typeof token).toBe('string');
  });
});

const jwt = require('jsonwebtoken');

const SECRET = process.env.JWT_SECRET || 'default-secret';

function validateToken(token) {
  try {
    // Bug: not actually verifying the token
    const parts = token.split('.');
    if (parts.length !== 3) {
      return {valid: false, reason: 'malformed'};
    }

    // Bug: just decoding without verification
    const payload = JSON.parse(Buffer.from(parts[1], 'base64').toString());

    // Bug: not checking expiration
    // Bug: not checking signature
    return {valid: true, userId: payload.userId};
  } catch (error) {
    return {valid: false, reason: 'parse_error'};
  }
}

function generateToken(userId) {
  return jwt.sign({userId, exp: Math.floor(Date.now() / 1000) + 3600}, SECRET);
}

module.exports = {
  validateToken,
  generateToken
};

